local LxNodeBase = require("LApp.component.LxNodeBase")
---@class BadgeGameNode:LxNodeBase
local BadgeGameNode = LxClass("BadgeGameNode", LxNodeBase)
------------------------------------------------------------------
function BadgeGameNode:BadgeGameNode()

    self._parentTrans = nil

    --加载的icon
    self._iconInst = nil
    self._data = nil

    self._uiIconBgTrans = nil
    self._uiIconTrans = nil

    self._uiIconBgComp = nil
    self._uiIconComp = nil

    self._iconPath = nil
    self._iconBgPath = nil

    self._defaultIconName = "public_default_item1"
    self._folder = "UI/Prefabs/panel"
    self._assetName = "BadgeGameNode"

    self._isEnus = gLGameLanguage:IsEnglishVersion()
end

function BadgeGameNode:Create(parentTran,data)
    self._data = data
    local tag = self._iconInst
    if not tag then
        tag = LDisplayPrefab:New()
        self._iconInst = tag
        local tran = parentTran
        tag:CreatePrefab(tran,self._folder,self._assetName)
        tag:SetLoadedFunction(function ()
            self:OnLoaded()
            if self.loadEdFunc then self.loadEdFunc(self) end
        end)
        -- tag:SetRenderPara("Object",0)
        tag:StartLoad()
    else
        self:OnLoaded()
        if self.loadEdFunc then self.loadEdFunc(self) end
    end
end

function BadgeGameNode:OnLoaded()
    if self._iconInst and self._iconInst._displayTrans then
        local isEnus = self._isEnus
        local data = self._data
        local findTran = CS.FindTrans
        local tran = self._iconInst:GetDisplayTrans()
        -- self._ImgLineBg = findTran(tran,"ImgLineBg")
        -- self._ImgLine = findTran(tran,"ImgLineBg/ImgLine")
        self._ImgStar = findTran(tran, "ImgStar")
        local _ImgIconBg = findTran(tran, "ImgIconBg")
        local _ImgIcon = findTran(tran, "ImgIcon")
        local _ImgLock = findTran(tran, "ImgLock")
        local _ImgFull = isEnus and findTran(tran, "ImgFullBg_En") or findTran(tran, "ImgFullBg")
        self._ImgSel = findTran(tran, "ImgSel")
        local _TxtFull =  isEnus and findTran(tran, "ImgFullBg_En/TxtFull_En")  or findTran(tran, "ImgFullBg/TxtFull")
        local _TxtName = findTran(tran, "TxtBg/TxtName")

        local ImgStarBg = findTran(tran,"ImgStarBg")
        local notActStarImg = data.notActStarImg
        if notActStarImg and ImgStarBg then
            self:SetImage(ImgStarBg, notActStarImg)
        end
        local actStarImg = data.actStarImg
        local ImgStar = findTran(tran,"ImgStar")
        if actStarImg and ImgStar then
            self:SetImage(ImgStar, actStarImg)
        end

        local chapterId = data.chapterId
        local chapterInfo = gModelBadgeGame:GetChapterById(chapterId)
        local barrierId = data.barrierId
        local star = chapterInfo and chapterInfo:GetBarrierStar(barrierId) or 0
        local sizeDel = self._ImgStar.transform.sizeDelta
        sizeDel.x = 30 * star
        self._ImgStar.transform.sizeDelta = sizeDel
        local barrierRef = GameTable.BadgeGameBarrierRef[barrierId]
        self:SetXTextContent(_TxtName, barrierRef.nameMap or "")
        -- local monRef = GameTable.MonsterFormationRef[barrierRef.monster]
        self:SetXTextContent(_TxtFull,ccClientText(40232) or "")
        CS.ShowObject(_ImgFull,star >= 3)

        local curBarrierId = chapterInfo:GetCorrespondingBarrierId()
        -- if monRef and monRef.icon then self._ImgIconSpr:SetSprite(monRef.icon) end
        -- CS.ShowObject(self._ImgLine.gameObject,curBarrierId>=barrierId)
        self:SetImage(_ImgIcon , barrierRef.icon)

        local isOpen = curBarrierId + 1 < barrierId
        --第一关高亮
        if curBarrierId <= 0 and (barrierId == 1 or barrierId == 99001) then
            isOpen = false
        end

        LxUiHelper.SetImageGray(_ImgIcon, isOpen)
        LxUiHelper.SetImageGray(_ImgIconBg, isOpen)
        CS.ShowObject(_ImgLock,isOpen)
        
        LxUiHelper.SetTransClick(tran, self._clickFunc)
        self:ResetDp()
    end
end
function BadgeGameNode:ResetDp()
    if not self._iconInst then
        return
    end
    local dpTrans =  self._iconInst:GetDisplayTrans()
    dpTrans.localScale = Vector3.one
    dpTrans.anchoredPosition3D = Vector3.zero
end
function BadgeGameNode:SetClickFunc(func)
    if func then self._clickFunc = func end
end

function BadgeGameNode:SetLoadedCallback(func)
    self.loadEdFunc = func
end

function BadgeGameNode:OnSelect(isSel)
    CS.ShowObject(self._ImgSel.transform.gameObject,isSel)
end
function BadgeGameNode:SetLineWidth(starPos,endPos)
    if not starPos or not endPos then return end
    if not self._ImgLineBg then return end
    local x = endPos[1]- starPos[1]
    local y = endPos[2] - starPos[2]
    local distance = math.sqrt(x^2 + y^2)
    local sizeDel = self._ImgLineBg.transform.sizeDelta
    sizeDel.x = distance
    self._ImgLineBg.sizeDelta = sizeDel
end
function BadgeGameNode:SetPostion(pos)
    if not pos then return end
    if not self._iconInst then return end
    pos.z = 0
    local tran = self._iconInst:GetDisplayTrans()
    tran.anchoredPosition3D = pos
end
function BadgeGameNode:setLineRotationZ(starPos,endPos)
    if not starPos or not endPos then return end
    if not self._ImgLineBg then return end
    local radian = math.atan2(endPos[2] - starPos[2],endPos[1] - starPos[1])
    local angle = math.radian2angle(radian)
    self._ImgLineBg.transform.eulerAngles = Vector3(0,0,angle)
end

function BadgeGameNode:Destroy()
    if self._iconInst then
        self._iconInst:Destroy()
        self._iconInst = nil
    end
    LxNodeBase.Dispose(self)
end

------------------------------------------------------------------------------
